#include <print>

class Resource {
public:
    explicit Resource(int id) : id_(id) {}

    Resource(const Resource&) = delete("Resource owns a unique handle; use clone() to copy explicitly");
    Resource& operator=(const Resource&) = delete("Resource owns a unique handle; use clone() to copy explicitly");

    Resource(Resource&&) = default;
    Resource& operator=(Resource&&) = default;

    Resource clone() const { return Resource(id_); }

    int id() const { return id_; }

private:
    int id_;
};

int main() {
    Resource a(1);
    Resource b = a.clone();      // explicit copy is allowed
    Resource c = std::move(a);   // move is allowed

    std::print("{} {} {}\n", b.id(), c.id(), a.id());
}

